parameters.jsCode:
const item = $input.item.json;

// Aggregate all external source data
const githubProfile = item.githubProfile || {};
const githubRepos = item.githubRepos || [];
const linkedinData = item.linkedinData || {};

// GitHub-derived evidence
const githubEvidence = {
  profileExists: !!githubProfile.login,
  publicRepos: githubProfile.public_repos || 0,
  followers: githubProfile.followers || 0,
  accountAgeDays: githubProfile.created_at
    ? Math.floor((Date.now() - new Date(githubProfile.created_at)) / 86400000)
    : 0,
  topLanguages: [...new Set(
    (githubRepos || [])
      .map(r => r.language)
      .filter(Boolean)
  )].slice(0, 10),
  repoNames: (githubRepos || []).map(r => r.name),
  stargazersTotal: (githubRepos || []).reduce((s, r) => s + (r.stargazers_count || 0), 0)
};

// LinkedIn-derived evidence
const linkedinEvidence = {
  profileExists: !!linkedinData.firstName,
  displayName: `${linkedinData.firstName || ''} ${linkedinData.lastName || ''}`.trim(),
  headline: linkedinData.headline || '',
  positions: linkedinData.positions?.values || [],
  educations: linkedinData.educations?.values || [],
  skills: (linkedinData.skills?.values || []).map(s => s.skill?.name).filter(Boolean)
};

return {
  json: {
    ...item,
    githubEvidence,
    linkedinEvidence
  }
};

parameters.text:
=You are an expert resume verification AI. Analyze the candidate's resume claims against external evidence and produce a structured JSON verification report.

## Candidate Information
Name: {{ $json.candidateName }}
Candidate ID: {{ $json.candidateId }}

## Resume Claims (parsed)
{{ JSON.stringify($json.parsedClaims, null, 2) }}

## GitHub Evidence
{{ JSON.stringify($json.githubEvidence, null, 2) }}

## LinkedIn Evidence
{{ JSON.stringify($json.linkedinEvidence, null, 2) }}

## Your Task
For each parsed claim, determine:
1. Verification status: VERIFIED / UNVERIFIED / FLAGGED / INCONCLUSIVE
2. Confidence score: 0.0 to 1.0
3. Evidence found or discrepancy noted
4. Specific flag reason (if FLAGGED)

Also assess:
- Do the skills claimed match the languages/repos found on GitHub?
- Does employment history align with LinkedIn positions?
- Are the claimed years of experience consistent across sources?
- Are there any date overlaps or impossible timelines?

Respond ONLY with valid JSON in this exact structure:
{
  "verifiedClaims": [
    {
      "claimType": "skill|employment|education|certification",
      "claimValue": "string describing the claim",
      "status": "VERIFIED|UNVERIFIED|FLAGGED|INCONCLUSIVE",
      "confidenceScore": 0.0,
      "evidenceSummary": "brief description",
      "flagReason": "null or reason string"
    }
  ],
  "discrepancies": [
    {
      "type": "date_overlap|skill_mismatch|employer_unverifiable|credential_gap",
      "description": "string",
      "severity": "HIGH|MEDIUM|LOW"
    }
  ],
  "overallNotes": "string"
}

parameters.jsCode:
const item = $input.item.json;

// Parse AI response
let aiResult = {};
try {
  const raw = item.output || item.response || item.text || '{}';
  const clean = raw.replace(/```json|```/g, '').trim();
  aiResult = JSON.parse(clean);
} catch(e) {
  aiResult = { verifiedClaims: [], discrepancies: [], overallNotes: 'Parse error: ' + e.message };
}

const claims = aiResult.verifiedClaims || [];
const discrepancies = aiResult.discrepancies || [];
const weights = item.scoreWeights || { employment: 0.35, education: 0.25, skills: 0.25, github: 0.10, certifications: 0.05 };
const flagThreshold = item.flagThreshold || 0.40;

// Group claims by type
const grouped = {};
claims.forEach(c => {
  const t = c.claimType || 'other';
  if (!grouped[t]) grouped[t] = [];
  grouped[t].push(c);
});

// Calculate category scores
const categoryScores = {};
Object.entries(grouped).forEach(([type, claimsArr]) => {
  const avg = claimsArr.reduce((s, c) => s + (c.confidenceScore || 0), 0) / claimsArr.length;
  const verified = claimsArr.filter(c => c.status === 'VERIFIED').length;
  const flagged = claimsArr.filter(c => c.status === 'FLAGGED').length;
  categoryScores[type] = {
    averageConfidence: +avg.toFixed(3),
    verifiedCount: verified,
    flaggedCount: flagged,
    totalCount: claimsArr.length,
    verificationRate: +(verified / claimsArr.length).toFixed(3)
  };
});

// GitHub bonus scoring
const gh = item.githubEvidence || {};
const githubScore = gh.profileExists
  ? Math.min(1.0, 0.4 + (gh.publicRepos > 10 ? 0.3 : gh.publicRepos * 0.03) + (gh.accountAgeDays > 365 ? 0.3 : gh.accountAgeDays / 365 * 0.3))
  : 0.0;

// Weighted overall authenticity score
const skillScore = categoryScores['skill']?.averageConfidence || 0;
const employmentScore = categoryScores['employment']?.averageConfidence || 0;
const educationScore = categoryScores['education']?.averageConfidence || 0;
const certScore = categoryScores['certification']?.averageConfidence || 0;

const overallScore = +(
  (employmentScore * weights.employment) +
  (educationScore * weights.education) +
  (skillScore * weights.skills) +
  (githubScore * weights.github) +
  (certScore * weights.certifications)
).toFixed(3);

// Determine overall verdict
let verdict = 'LOW_CONFIDENCE';
if (overallScore >= 0.80) verdict = 'HIGHLY_AUTHENTIC';
else if (overallScore >= 0.60) verdict = 'LIKELY_AUTHENTIC';
else if (overallScore >= 0.40) verdict = 'PARTIALLY_VERIFIED';
else if (overallScore >= 0.20) verdict = 'SUSPICIOUS';

const highSeverityFlags = discrepancies.filter(d => d.severity === 'HIGH').length;
if (highSeverityFlags >= 2) verdict = 'FLAGGED_FOR_REVIEW';

// Final report
const report = {
  candidateId: item.candidateId,
  candidateName: item.candidateName,
  verifiedAt: new Date().toISOString(),
  overallAuthenticityScore: overallScore,
  verdict,
  categoryScores,
  githubScore: +githubScore.toFixed(3),
  discrepancies,
  flaggedClaimsCount: claims.filter(c => c.status === 'FLAGGED').length,
  verifiedClaimsCount: claims.filter(c => c.status === 'VERIFIED').length,
  totalClaimsAnalyzed: claims.length,
  verifiedClaims: claims,
  overallNotes: aiResult.overallNotes || '',
  linkedinUrl: item.linkedinUrl,
  githubUsername: item.githubUsername,
  status: 'Completed'
};

return { json: { ...item, report } };

